function _updateStarBtn(){const btn=document.getElementById("watchlistStarBtn");if(!btn)return;const symbol=document.getElementById("symbolInput")?.value?.trim();const market=document.getElementById("marketSelect")?.value||"crypto";const exchange=document.getElementById("exchangeSelect")?.value||"pionex";if(!symbol){btn.classList.remove("active","starred");return;}
const key=`${market}:${exchange}:${symbol}`;const inWl=_watchlist.some(w=>`${w.market}:${w.exchange || ""}:${w.symbol}`===key);btn.classList.toggle("active",inWl);btn.classList.toggle("starred",inWl);}
let _watchlist=[];let _wlPriceCache={};function _loadWatchlist(){try{_watchlist=JSON.parse(localStorage.getItem("watchlist")||"[]");}catch{_watchlist=[];}}
function _saveWatchlist(){try{localStorage.setItem("watchlist",JSON.stringify(_watchlist));}catch{}}
